mapper.update:
update cert_issue_history h
	set h.printed_at = sysdate
where h.issue_seq = #{issue_seq}
	and h.cert_request_seq = #{cert_request_seq}
      and h.printed_at is null
      and exists (
          select 1
            from cert_issue_request cir
           where cir.cert_request_seq = h.cert_request_seq
              and cir.users_id = #{loginId}
              and cir.status = 'APPROVED'
	       )
